const getRecentTimeList = (type) => {
const end = new Date(); // 当前时间
const start = new Date();

if (type === 'day') {
  // 近 7 天：从 6 天前的 00:00:00 到 今天的 23:59:59 (或者当前时间)
  start.setDate(end.getDate() - 6);

  // 格式化为 YYYY-MM-DD
  function formatDate(d) { d.toISOString().split('T')[0] };
  return [formatDate(start), formatDate(end)];
}

if (type === 'hour') {
  // 最近 24 小时
  start.setHours(end.getHours() - 24);

  // 格式化为 YYYY-MM-DD HH:mm:ss (Element Plus datetimerange 标准格式)
  function formatDateTime(d) {
    const date = d.toISOString().split('T')[0];
    const time = d.toTimeString().split(' ')[0]; // 获取 HH:mm:ss
    return `${date} ${time}`;
  };
  return [formatDateTime(start), formatDateTime(end)];
}

return [];
};
const handleTypeChange = () => {
// 根据当前选中的时间类型，获取最近的时间数组
state.timeRange = getRecentTimeList(state.type);
console.log('state.timeRange', state.type, state.timeRange);
// 格式化时间
formatTime();
};
const formatTime = () => {
if (state.type === 'hour') {
  state.startTime = state.timeRange[0].substr(0, 16);
  state.endTime = state.timeRange[1].substr(0, 16);
} else if (state.type === 'day') {
  state.startTime = state.timeRange[0].substr(0, 10);
  state.endTime = state.timeRange[1].substr(0, 10);
}

};
